Шаблон Описание Пример <code>%</code> Любое количество символов <code>'Иван%'</code> <code>_</code> Один любой символ <code>'А_ексей'</code> <pre><code>-- Имена, начинающиеся на "Иван"
SELECT * FROM users WHERE first_name LIKE 'Иван%';

-- Имена, заканчивающиеся на "ов"
SELECT * FROM users WHERE last_name LIKE '%ов';
</code></pre>
